import json, csv
import pandas as pd
from datetime import datetime


def norm_date(v):
    if v is None:
        return None
    s = str(v).strip()
    if not s:
        return None
    for fmt in ("%Y-%m-%d", "%Y/%m/%d", "%m/%d/%Y", "%d-%m-%Y", "%Y-%m-%dT%H:%M:%S"):
        try:
            return datetime.strptime(s, fmt).strftime("%Y-%m-%d")
        except ValueError:
            continue
    try:
        return pd.to_datetime(s).strftime("%Y-%m-%d")
    except Exception:
        return s


def load_source_a():
    out = {}
    for r in json.load(open("/data/source_a/users.json")):
        uid = int(r.get("user_id", r.get("id", r.get("userId"))))
        out[uid] = {
            "user_id": uid,
            "name": r.get("full_name") or r.get("name") or r.get("userName"),
            "email": r.get("email") or r.get("email_address"),
            "created_date": norm_date(r.get("registration_date") or r.get("created_at") or r.get("joined")),
            "status": r.get("status"),
        }
    return out


def load_source_b():
    out = {}
    for r in csv.DictReader(open("/data/source_b/users.csv")):
        uid = int(r.get("user_id") or r.get("id") or r.get("userId"))
        status = r.get("status")
        out[uid] = {
            "user_id": uid,
            "name": r.get("full_name") or r.get("name") or r.get("userName"),
            "email": r.get("email") or r.get("email_address"),
            "created_date": norm_date(r.get("registration_date") or r.get("created_at") or r.get("joined")),
            "status": status if status else None,
        }
    return out


def load_source_c():
    out = {}
    df = pd.read_parquet("/data/source_c/users.parquet")
    for r in df.to_dict("records"):
        uid = int(r.get("user_id", r.get("id", r.get("userId"))))
        out[uid] = {
            "user_id": uid,
            "name": r.get("full_name") or r.get("name") or r.get("userName"),
            "email": r.get("email") or r.get("email_address"),
            "created_date": norm_date(r.get("registration_date") or r.get("created_at") or r.get("joined")),
            "status": r.get("status"),
        }
    return out


sources = {
    "source_a": load_source_a(),
    "source_b": load_source_b(),
    "source_c": load_source_c(),
}
priority = ["source_a", "source_b", "source_c"]

all_ids = sorted(set().union(*[set(s.keys()) for s in sources.values()]))
conflict_fields = ["name", "email", "created_date", "status"]

merged = []
conflicts = []
for uid in all_ids:
    present = [(sn, sources[sn][uid]) for sn in priority if uid in sources[sn]]
    record = {"user_id": uid}
    for field in ["name", "email", "created_date", "status"]:
        selected = None
        for sn, rec in present:
            if rec.get(field) is not None:
                selected = rec.get(field)
                break
        record[field] = selected
    merged.append(record)

    for field in conflict_fields:
        vals = {sn: rec.get(field) for sn, rec in present if rec.get(field) is not None}
        distinct = set(vals.values())
        if len(distinct) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": vals,
                "selected": record[field],
            })

out_df = pd.DataFrame(merged, columns=["user_id", "name", "email", "created_date", "status"])
out_df["user_id"] = out_df["user_id"].astype("int64")
for col in ["name", "email", "created_date", "status"]:
    out_df[col] = out_df[col].astype("object")
out_df.to_parquet("/app/merged_users.parquet", index=False)

report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
json.dump(report, open("/app/conflicts.json", "w"), indent=2)

print(out_df.to_string())
print(json.dumps(report, indent=2))

